import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { api } from "../api";
import { useAuth } from "../context/AuthContext";

export default function CarDetail() {
  const { id } = useParams();
  const { token } = useAuth();
  const [car, setCar] = useState(null);
  const [error, setError] = useState("");
  const [favorited, setFavorited] = useState(false);

  useEffect(() => {
    api
      .getCar(id)
      .then(setCar)
      .catch((err) => setError(err.message));
  }, [id]);

  async function handleFavorite() {
    try {
      await api.addFavorite(id, token);
      setFavorited(true);
    } catch (err) {
      setError(err.message);
    }
  }

  if (error) return <p className="form-error">{error}</p>;
  if (!car) return <p>Loading…</p>;

  return (
    <section className="page car-detail">
      {car.image_url && (
        <img
          src={car.image_url}
          alt={`${car.year} ${car.make} ${car.model}`}
          style={{ width: "100%", maxWidth: 480, borderRadius: "var(--radius)", marginBottom: 20, display: "block" }}
        />
      )}
      <h1>
        {car.year} {car.make} {car.model}
      </h1>
      <p className="car-detail__price">${Number(car.price).toLocaleString()}</p>
      <p className="car-detail__meta">{Number(car.mileage).toLocaleString()} miles</p>

      {token ? (
        <button onClick={handleFavorite} disabled={favorited}>
          {favorited ? "Saved to favorites" : "Save to favorites"}
        </button>
      ) : (
        <p className="hint">Log in to save this car to your favorites.</p>
      )}
    </section>
  );
}
